import { MakeLogicType, actions, connect, kea, key, listeners, path, props, reducers } from 'kea'
import { loaders } from 'kea-loaders'

import { lemonToast } from '@posthog/lemon-ui'

import api from 'lib/api'

import { ExternalDataSourceSchema, SchemaIncrementalFieldsResponse } from '~/types'

import { sourceManagementLogic } from '../../shared/logics/sourceManagementLogic'

export interface SyncMethodModalLogicProps {
    schema: ExternalDataSourceSchema
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface syncMethodModalLogicValues {
    currentSyncMethodModalSchema: ExternalDataSourceSchema | null;
    saveButtonIsLoading: boolean;
    schemaIncrementalFields: SchemaIncrementalFieldsResponse | null;
    schemaIncrementalFieldsLoading: boolean;
    syncMethodModalIsOpen: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface syncMethodModalLogicActions {
    loadSources: () => {
        value: true;
    }; // sourceManagementLogic
    updateSchema: (schema: ExternalDataSourceSchema) => ExternalDataSourceSchema; // sourceManagementLogic
    updateSchemaFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    }; // sourceManagementLogic
    updateSchemaSuccess: (schemas: null, payload?: ExternalDataSourceSchema | undefined) => {
        payload?: ExternalDataSourceSchema;
        schemas: null;
    }; // sourceManagementLogic
    closeSyncMethodModal: () => {
        value: true;
    };
    loadSchemaIncrementalFields: (schemaId: string) => string;
    loadSchemaIncrementalFieldsFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadSchemaIncrementalFieldsSuccess: (schemaIncrementalFields: SchemaIncrementalFieldsResponse, payload?: string) => {
        schemaIncrementalFields: SchemaIncrementalFieldsResponse;
        payload?: string;
    };
    openSyncMethodModal: (schema: ExternalDataSourceSchema) => {
        schema: ExternalDataSourceSchema;
    };
    resetSchemaIncrementalFields: () => any;
    resetSchemaIncrementalFieldsFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    resetSchemaIncrementalFieldsSuccess: (schemaIncrementalFields: null, payload?: any) => {
        schemaIncrementalFields: null;
        payload?: any;
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface syncMethodModalLogicMeta {
    key: string;
}

export type syncMethodModalLogicType = MakeLogicType<syncMethodModalLogicValues, syncMethodModalLogicActions, SyncMethodModalLogicProps, syncMethodModalLogicMeta>;

export const syncMethodModalLogic = kea<syncMethodModalLogicType>([
    path(['products', 'dataWarehouse', 'syncMethodModalLogic']),
    props({ schema: {} } as SyncMethodModalLogicProps),
    key((props) => props.schema.id),
    connect(() => ({
        actions: [sourceManagementLogic, ['updateSchema', 'updateSchemaSuccess', 'updateSchemaFailure', 'loadSources']],
    })),
    actions({
        openSyncMethodModal: (schema: ExternalDataSourceSchema) => ({ schema }),
        closeSyncMethodModal: true,
    }),
    loaders({
        schemaIncrementalFields: [
            null as SchemaIncrementalFieldsResponse | null,
            {
                loadSchemaIncrementalFields: async (schemaId: string) => {
                    try {
                        return await api.externalDataSchemas.incremental_fields(schemaId)
                    } catch (e: any) {
                        lemonToast.error(e?.data?.message ?? e?.message ?? e)
                        throw e
                    }
                },
                resetSchemaIncrementalFields: () => null,
            },
        ],
    }),
    reducers({
        syncMethodModalIsOpen: [
            false as boolean,
            {
                openSyncMethodModal: () => true,
                closeSyncMethodModal: () => false,
            },
        ],
        currentSyncMethodModalSchema: [
            null as ExternalDataSourceSchema | null,
            {
                openSyncMethodModal: (_, { schema }) => schema,
                closeSyncMethodModal: () => null,
            },
        ],
        saveButtonIsLoading: [
            false as boolean,
            {
                updateSchema: () => true,
                updateSchemaFailure: () => false,
                updateSchemaSuccess: () => false,
            },
        ],
    }),
    listeners(({ actions }) => ({
        updateSchemaSuccess: () => {
            actions.loadSources()
            actions.resetSchemaIncrementalFields()
            actions.closeSyncMethodModal()
        },
    })),
])
